package com.example.biometricauth;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;

import androidx.activity.ComponentActivity;
import androidx.annotation.NonNull;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;

import java.util.concurrent.Executor;

public class LoginActivity extends ComponentActivity {

    private static final String PREFS_NAME = "app_prefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_AUTHENTICATED = "authenticated";

    private EditText usernameEditText;
    private EditText passwordEditText;
    private CheckBox enableBiometricCheckBox;
    private SharedPreferences sharedPreferences;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);

        if (sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false)) {
            if (canUseBiometrics()) {
                setupBiometricPrompt();
                showBiometricPrompt();
                return;
            }
        }

        setContentView(R.layout.activity_login);

        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        enableBiometricCheckBox = findViewById(R.id.enableBiometricCheckBox);
        Button loginButton = findViewById(R.id.loginButton);

        enableBiometricCheckBox.setChecked(sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false));

        loginButton.setOnClickListener(v -> {
            String username = usernameEditText.getText().toString().trim();
            String password = passwordEditText.getText().toString().trim();

            if (isValidLogin(username, password)) {
                sharedPreferences.edit()
                        .putBoolean(KEY_BIOMETRIC_ENABLED, enableBiometricCheckBox.isChecked())
                        .putBoolean(KEY_AUTHENTICATED, true)
                        .apply();
                navigateToMain();
            } else {
                Toast.makeText(this, "Invalid username or password", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private boolean isValidLogin(String username, String password) {
        return !username.isEmpty() && !password.isEmpty();
    }

    private boolean canUseBiometrics() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int result = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);
        return result == BiometricManager.BIOMETRIC_SUCCESS;
    }

    private void setupBiometricPrompt() {
        Executor executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, true).apply();
                navigateToMain();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                showLoginScreen();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Toast.makeText(LoginActivity.this, "Fingerprint not recognized", Toast.LENGTH_SHORT).show();
            }
        });

        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Login")
                .setSubtitle("Use your fingerprint to unlock the app")
                .setNegativeButtonText("Use password")
                .build();
    }

    private void showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo);
    }

    private void showLoginScreen() {
        setContentView(R.layout.activity_login);

        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        enableBiometricCheckBox = findViewById(R.id.enableBiometricCheckBox);
        Button loginButton = findViewById(R.id.loginButton);

        enableBiometricCheckBox.setChecked(sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false));

        loginButton.setOnClickListener(v -> {
            String username = usernameEditText.getText().toString().trim();
            String password = passwordEditText.getText().toString().trim();

            if (isValidLogin(username, password)) {
                sharedPreferences.edit()
                        .putBoolean(KEY_BIOMETRIC_ENABLED, enableBiometricCheckBox.isChecked())
                        .putBoolean(KEY_AUTHENTICATED, true)
                        .apply();
                navigateToMain();
            } else {
                Toast.makeText(this, "Invalid username or password", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void navigateToMain() {
        startActivity(new Intent(this, MainActivity.class));
        finish();
    }
}

package com.example.biometricauth;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;

import androidx.activity.ComponentActivity;

public class SplashActivity extends ComponentActivity {

    private static final String PREFS_NAME = "app_prefs";
    private static final String KEY_AUTHENTICATED = "authenticated";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        SharedPreferences sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        boolean authenticated = sharedPreferences.getBoolean(KEY_AUTHENTICATED, false);

        if (authenticated) {
            startActivity(new Intent(this, MainActivity.class));
        } else {
            startActivity(new Intent(this, LoginActivity.class));
        }
        finish();
    }
}

package com.example.biometricauth;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.widget.Button;

import androidx.activity.ComponentActivity;

public class MainActivity extends ComponentActivity {

    private static final String PREFS_NAME = "app_prefs";
    private static final String KEY_AUTHENTICATED = "authenticated";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        Button logoutButton = findViewById(R.id.logoutButton);
        logoutButton.setOnClickListener(v -> {
            SharedPreferences sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
            sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, false).apply();
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
    }
}

